#define MAX_PHYS_PAGES (1U << 20)

typedef void (*trap_handler_t)(ExceptionInfo *);

static trap_handler_t trap_vector[TRAP_VECTOR_SIZE];
static struct pte region0_page_table[PAGE_TABLE_LEN];
static struct pte region1_page_table[PAGE_TABLE_LEN];

static unsigned char frame_in_use[MAX_PHYS_PAGES];
static unsigned int num_phys_pages;

static int vm_enabled;
static void *kernel_brk;

static void
panic_trap(ExceptionInfo *info)
{
    int vector = -1;
    int code = 0;

    if (info != NULL) {
        vector = info->vector;
        code = info->code;
    }

    TracePrintf(0, "Unhandled trap/exception vector=%d code=%d\n", vector, code);
    Halt();
}

static void
mark_frame_used(unsigned int pfn)
{
    if (pfn < num_phys_pages) {
        frame_in_use[pfn] = 1;
    }
}

static void
mark_range_used(unsigned long start, unsigned long end)
{
    unsigned long addr;
    unsigned long first_page;
    unsigned long last_page_exclusive;

    if (end <= start) {
        return;
    }

    first_page = DOWN_TO_PAGE(start);
    last_page_exclusive = UP_TO_PAGE(end);
    for (addr = first_page; addr < last_page_exclusive; addr += PAGESIZE) {
        mark_frame_used((unsigned int)(addr >> PAGESHIFT));
    }
}

static int
alloc_frame(unsigned int *pfn_out)
{
    unsigned int pfn;

    for (pfn = 0; pfn < num_phys_pages; pfn++) {
        if (!frame_in_use[pfn]) {
            frame_in_use[pfn] = 1;
            *pfn_out = pfn;
            return 0;
        }
    }

    return -1;
}

static void
free_frame(unsigned int pfn)
{
    if (pfn < num_phys_pages) {
        frame_in_use[pfn] = 0;
    }
}

static void
map_region0_kernel_stack(void)
{
    unsigned long va;

    for (va = KERNEL_STACK_BASE; va < KERNEL_STACK_LIMIT; va += PAGESIZE) {
        unsigned int vpn = (unsigned int)(va >> PAGESHIFT);
        region0_page_table[vpn].valid = 1;
        region0_page_table[vpn].kprot = PROT_READ | PROT_WRITE;
        region0_page_table[vpn].uprot = PROT_NONE;
        region0_page_table[vpn].pfn = (unsigned int)(va >> PAGESHIFT);
    }
}

