/*
 * KernelStart - Initialize the Yalnix kernel.
 *
 * Called by the hardware boot sequence to initialize the kernel.
 * Must set up virtual memory, create the idle and init processes,
 * set up trap handlers, and begin running user processes.
 */
void
KernelStart(ExceptionInfo *info, unsigned int pmem_size,
            void *orig_brk, char **cmd_args)
{
    (void)cmd_args;

    kernel_brk = orig_brk;
    vm_enabled = 0;

    memset(region0_page_table, 0, sizeof(region0_page_table));
    memset(region1_page_table, 0, sizeof(region1_page_table));

    init_trap_vector();
    map_region0_kernel_stack();
    map_initial_region1(orig_brk);
    init_frame_allocator(pmem_size, orig_brk);

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)trap_vector);
    WriteRegister(REG_PTR0, (RCS421RegVal)region0_page_table);
    WriteRegister(REG_PTR1, (RCS421RegVal)region1_page_table);
    WriteRegister(REG_VM_ENABLE, 1);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_ALL);

    vm_enabled = 1;

    /*
     * If no init process is set up yet, returning in kernel mode avoids
     * dropping into an unmapped user context.
     */
    if (info != NULL) {
        info->psr |= PSR_MODE;
    }
}

/*
 * SetKernelBrk - Adjust the kernel heap break.
 *
 * Called by malloc/free in the kernel to grow/shrink the heap.
 * Before virtual memory is enabled, simply track the break.
 * After VM is enabled, must allocate/free physical pages.
 */
int
SetKernelBrk(void *addr)
{
    unsigned long old_brk;
    unsigned long new_brk;
    unsigned long old_end_page;
    unsigned long new_end_page;
    unsigned long va;

    if (addr == NULL) {
        return -1;
    }

    old_brk = (unsigned long)kernel_brk;
    new_brk = (unsigned long)addr;

    if (new_brk < VMEM_1_BASE || new_brk > VMEM_1_LIMIT) {
        return -1;
    }

    if (new_brk < old_brk) {
        return -1;
    }

    if (!vm_enabled) {
        kernel_brk = addr;
        return 0;
    }

    old_end_page = (unsigned long)UP_TO_PAGE(old_brk);
    new_end_page = (unsigned long)UP_TO_PAGE(new_brk);

    for (va = old_end_page; va < new_end_page; va += PAGESIZE) {
        unsigned int pfn;
        unsigned int vpn;

        if (alloc_frame(&pfn) < 0) {
            unsigned long rollback_va;
            for (rollback_va = old_end_page; rollback_va < va; rollback_va += PAGESIZE) {
                unsigned int rb_vpn = (unsigned int)((rollback_va - VMEM_1_BASE) >> PAGESHIFT);
                if (region1_page_table[rb_vpn].valid) {
                    free_frame(region1_page_table[rb_vpn].pfn);
                    memset(&region1_page_table[rb_vpn], 0, sizeof(struct pte));
                }
            }
            WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
            return -1;
        }

        vpn = (unsigned int)((va - VMEM_1_BASE) >> PAGESHIFT);
        region1_page_table[vpn].valid = 1;
        region1_page_table[vpn].kprot = PROT_READ | PROT_WRITE;
        region1_page_table[vpn].uprot = PROT_NONE;
        region1_page_table[vpn].pfn = pfn;
    }

    if (new_end_page != old_end_page) {
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
    }

    kernel_brk = addr;
    return 0;
}

