 55	    for (addr = first_page; addr < last_page_exclusive; addr += PAGESIZE) {
 56	        mark_frame_used((unsigned int)(addr >> PAGESHIFT));
 57	    }
 58	}
 59	
 60	static int
 61	alloc_frame(unsigned int *pfn_out)
 62	{
 63	    unsigned int pfn;
 64	
 65	    for (pfn = 0; pfn < num_phys_pages; pfn++) {
 66	        if (!frame_in_use[pfn]) {
 67	            frame_in_use[pfn] = 1;
 68	            *pfn_out = pfn;
 69	            return 0;
 70	        }
 71	    }
 72	
 73	    return -1;
 74	}
 75	
 76	static void
 77	free_frame(unsigned int pfn)
 78	{
 79	    if (pfn < num_phys_pages) {
 80	        frame_in_use[pfn] = 0;
 81	    }
 82	}
