 84	static void
 85	map_region0_kernel_stack(void)
 86	{
 87	    unsigned long va;
 88	
 89	    for (va = KERNEL_STACK_BASE; va < KERNEL_STACK_LIMIT; va += PAGESIZE) {
 90	        unsigned int vpn = (unsigned int)(va >> PAGESHIFT);
 91	        region0_page_table[vpn].valid = 1;
 92	        region0_page_table[vpn].kprot = PROT_READ | PROT_WRITE;
 93	        region0_page_table[vpn].uprot = PROT_NONE;
 94	        region0_page_table[vpn].pfn = (unsigned int)(va >> PAGESHIFT);
 95	    }
 96	}
