 98	static void
 99	map_initial_region1(void *orig_brk)
100	{
101	    unsigned long text_end;
102	    unsigned long heap_end;
103	    unsigned long va;
104	
105	    text_end = (unsigned long)&_etext;
106	    heap_end = (unsigned long)UP_TO_PAGE(orig_brk);
107	
108	    for (va = VMEM_1_BASE; va < text_end; va += PAGESIZE) {
109	        unsigned int vpn = (unsigned int)((va - VMEM_1_BASE) >> PAGESHIFT);
110	        region1_page_table[vpn].valid = 1;
111	        region1_page_table[vpn].kprot = PROT_READ | PROT_EXEC;
112	        region1_page_table[vpn].uprot = PROT_NONE;
113	        region1_page_table[vpn].pfn = (unsigned int)(va >> PAGESHIFT);
114	    }
115	
116	    for (va = text_end; va < heap_end; va += PAGESIZE) {
117	        unsigned int vpn = (unsigned int)((va - VMEM_1_BASE) >> PAGESHIFT);
118	        region1_page_table[vpn].valid = 1;
119	        region1_page_table[vpn].kprot = PROT_READ | PROT_WRITE;
120	        region1_page_table[vpn].uprot = PROT_NONE;
121	        region1_page_table[vpn].pfn = (unsigned int)(va >> PAGESHIFT);
122	    }
123	}
