126	init_trap_vector(void)
127	{
128	    int i;
129	
130	    for (i = 0; i < TRAP_VECTOR_SIZE; i++) {
131	        trap_vector[i] = NULL;
132	    }
133	
134	    trap_vector[TRAP_KERNEL] = panic_trap;
135	    trap_vector[TRAP_CLOCK] = panic_trap;
136	    trap_vector[TRAP_ILLEGAL] = panic_trap;
