146	static void
147	init_frame_allocator(unsigned int pmem_size, void *orig_brk)
148	{
149	    if ((pmem_size >> PAGESHIFT) > MAX_PHYS_PAGES) {
150	        num_phys_pages = MAX_PHYS_PAGES;
151	    } else {
152	        num_phys_pages = pmem_size >> PAGESHIFT;
153	    }
154	
155	    memset(frame_in_use, 0, sizeof(frame_in_use));
156	
157	    mark_range_used(KERNEL_STACK_BASE, KERNEL_STACK_LIMIT);
158	    mark_range_used(VMEM_1_BASE, (unsigned long)UP_TO_PAGE(orig_brk));
159	}
