161	/*
162	 * KernelStart - Initialize the Yalnix kernel.
163	 *
164	 * Called by the hardware boot sequence to initialize the kernel.
165	 * Must set up virtual memory, create the idle and init processes,
166	 * set up trap handlers, and begin running user processes.
167	 */
168	void
169	KernelStart(ExceptionInfo *info, unsigned int pmem_size,
170	            void *orig_brk, char **cmd_args)
171	{
172	    (void)cmd_args;
173	
174	    kernel_brk = orig_brk;
175	    vm_enabled = 0;
176	
177	    memset(region0_page_table, 0, sizeof(region0_page_table));
178	    memset(region1_page_table, 0, sizeof(region1_page_table));
179	
180	    init_trap_vector();
181	    map_region0_kernel_stack();
182	    map_initial_region1(orig_brk);
183	    init_frame_allocator(pmem_size, orig_brk);
184	
185	    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)trap_vector);
186	    WriteRegister(REG_PTR0, (RCS421RegVal)region0_page_table);
187	    WriteRegister(REG_PTR1, (RCS421RegVal)region1_page_table);
188	    WriteRegister(REG_VM_ENABLE, 1);
189	    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_ALL);
190	
191	    vm_enabled = 1;
192	
193	    (void)info;
194	}
