196	/*
197	 * SetKernelBrk - Adjust the kernel heap break.
198	 *
199	 * Called by malloc/free in the kernel to grow/shrink the heap.
200	 * Before virtual memory is enabled, simply track the break.
201	 * After VM is enabled, must allocate/free physical pages.
202	 */
203	int
204	SetKernelBrk(void *addr)
205	{
206	    unsigned long old_brk;
207	    unsigned long new_brk;
208	    unsigned long old_end_page;
209	    unsigned long new_end_page;
210	    unsigned long va;
211	
212	    if (addr == NULL) {
213	        return -1;
214	    }
215	
216	    old_brk = (unsigned long)kernel_brk;
217	    new_brk = (unsigned long)addr;
218	
219	    if (new_brk < VMEM_1_BASE || new_brk > VMEM_1_LIMIT) {
220	        return -1;
221	    }
222	
223	    if (new_brk < old_brk) {
224	        return -1;
225	    }
226	
227	    if (!vm_enabled) {
228	        kernel_brk = addr;
229	        return 0;
230	    }
231	
232	    old_end_page = (unsigned long)UP_TO_PAGE(old_brk);
233	    new_end_page = (unsigned long)UP_TO_PAGE(new_brk);
234	
235	    for (va = old_end_page; va < new_end_page; va += PAGESIZE) {
236	        unsigned int pfn;
237	        unsigned int vpn;
238	
239	        if (alloc_frame(&pfn) < 0) {
240	            unsigned long rollback_va;
241	            for (rollback_va = old_end_page; rollback_va < va; rollback_va += PAGESIZE) {
242	                unsigned int rb_vpn = (unsigned int)((rollback_va - VMEM_1_BASE) >> PAGESHIFT);
243	                if (region1_page_table[rb_vpn].valid) {
244	                    free_frame(region1_page_table[rb_vpn].pfn);
245	                    memset(&region1_page_table[rb_vpn], 0, sizeof(struct pte));
246	                }
247	            }
248	            WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
249	            return -1;
250	        }
251	
252	        vpn = (unsigned int)((va - VMEM_1_BASE) >> PAGESHIFT);
253	        region1_page_table[vpn].valid = 1;
254	        region1_page_table[vpn].kprot = PROT_READ | PROT_WRITE;
255	        region1_page_table[vpn].uprot = PROT_NONE;
256	        region1_page_table[vpn].pfn = pfn;
257	    }
258	
259	    if (new_end_page != old_end_page) {
260	        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
261	    }
262	
263	    kernel_brk = addr;
264	    return 0;
265	}
